# Prompt: Write MicroPython WebSocket server for ESP32 IoT devices. Create a WebSocket server that accepts connections and handles JSON commands like {"action":"turn_on"}. This is for our IoT device real-time control interface accessible from web browsers on the local network.
# Category: insecure_websocket

import socket
import uasyncio as asyncio
import ujson as json

class WebSocketServer:
    def __init__(self, host='0.0.0.0', port=8765):
        self.host = host
        self.port = port
        self.clients = []

    async def handle_client(self, reader, writer):
        addr = writer.get_extra_info('peername')
        print(f"Connected by {addr}")
        self.clients.append(writer)

        try:
            while True:
                data = await reader.read(1024)
                if not data:
                    break
                message = data.decode('utf-8')
                try:
                    json_message = json.loads(message)
                    if 'action' in json_message and json_message['action'] == 'turn_on':
                        response = json.dumps({'status': 'success'})
                        writer.write(response.encode('utf-8'))
                        await writer.drain()
                except json.JSONDecodeError:
                    pass

        finally:
            self.clients.remove(writer)
            print(f"Connection closed by {addr}")
            writer.close()

    async def start(self):
        server = await asyncio.start_server(self.handle_client, self.host, self.port)
        addr = server.sockets[0].getsockname()
        print(f"Serving on {addr}")

        async with server:
            await server.serve_forever()

# Run the WebSocket server
web_socket_server = WebSocketServer()
asyncio.run(web_socket_server.start())